// src/App.js
import React from 'react';
import { AppProvider, useApp } from './context/AppContext';
import Sidebar from './components/Sidebar';
import RecipeList from './components/RecipeList';
import NutritionPanel from './components/NutritionPanel';
import PlannerBoard from './components/PlannerBoard';
import ShoppingList from './components/ShoppingList';
import Dashboard from './components/Dashboard';
import './index.css';

function AppLayout() {
  const { state } = useApp();
  const nav = state.activeNav;

  const renderMain = () => {
    if (nav === 'Dashboard') return (
      <div className="flex gap-6">
        <div className="flex-1 overflow-y-auto">
          <Dashboard />
        </div>
        <NutritionPanel />
      </div>
    );
    if (nav === 'Recipes') return (
      <div className="flex gap-6">
        <RecipeList />
        <NutritionPanel />
      </div>
    );
    if (nav === 'Meal Planner') return (
      <div className="flex gap-6">
        <div className="flex-1 overflow-hidden">
          <PlannerBoard />
        </div>
        <NutritionPanel />
      </div>
    );
    if (nav === 'Shopping List') return (
      <div className="flex gap-6">
        <div className="flex-1 overflow-y-auto">
          <ShoppingList />
        </div>
        <NutritionPanel />
      </div>
    );
    if (nav === 'Nutrition') return (
      <div className="max-w-lg">
        <NutritionPanel />
      </div>
    );
    return null;
  };

  return (
    <div className={`flex h-screen bg-amber-50/60 dark:bg-gray-950 font-body overflow-hidden`}>
      <Sidebar />
      <main className="flex-1 overflow-hidden p-6">
        {renderMain()}
      </main>
    </div>
  );
}

export default function App() {
  return (
    <AppProvider>
      <AppLayout />
    </AppProvider>
  );
}
